INSERT INTO `notification_email_template` VALUES (1,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nA Purchase Requisition with Reference No {#PURCHASE_REQUISITION_NUMBER#} has been raised by {#RAISED_BY#} for approval.\nYou can review & approve/reject it using the following link: {#EMAIL_LINK#}.\n\nBest regards,\nCompany Admin','Purchase Requisition Approval Request',NULL,NULL,1,2),(2,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#RAISED_BY#},\n\nYour Purchase Requisition with Reference No {#PURCHASE_REQUISITION_NUMBER#} has been approved by {#ACTIONED_BY#}.\nRemark: {#REMARKS#}.\n\nBest regards,\nCompany Admin','Purchase Requisition Approved',NULL,NULL,1,3),(3,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nYour Purchase Requisition with Reference No {#PURCHASE_REQUISITION_NUMBER#} has been rejected due to the following reason:\n{#REMARKS#}\nRejected by: {#ACTIONED_BY#}\n\nBest regards,\nCompany Admin','Purchase Requisition Rejected',NULL,NULL,1,4),(4,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nA new Purchase Order with Reference No {#PURCHASE_ORDER_NUMBER#} has been raised by {#RAISED_BY#} and assigned to you for verification.\nYou can review & verify it using the following link: {#EMAIL_LINK#}.\n\nBest regards,\nCompany Admin','Purchase Order Verification Request',NULL,NULL,5,6),(5,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nYour Purchase Order with Reference No {#PURCHASE_ORDER_NUMBER#} has been verified by {#ACTIONED_BY#}.\nVerification Remark: {#REMARKS#}.\n\nBest regards,\nCompany Admin','Purchase Order Verified',NULL,NULL,5,7),(6,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nA new Purchase Order with Reference No {#PURCHASE_ORDER_NUMBER#} has been raised by {#RAISED_BY#} and verified by {#ACTIONED_BY#} and assigned to you for approval.\nYou can review & approve/reject it using the following link: {#EMAIL_LINK#}.\n\nVerifier Remark: {#REMARKS#}.\n\nBest regards,\nCompany Admin','Purchase Order Approval Request',NULL,NULL,5,8),(7,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nYour Purchase Order with Reference No {#PURCHASE_ORDER_NUMBER#} has been approved by {#ACTIONED_BY#}.\nApprover Level: {#APPROVAL_LEVEL#}.\nApproval Remark: {#REMARKS#}.\n\nBest regards,\nCompany Admin','Purchase Order Approved',NULL,NULL,5,9),(8,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nYour Purchase Order with Reference No {#PURCHASE_ORDER_NUMBER#} has been rejected at {#APPROVER_LEVEL#} by {#ACTIONED_BY#} due to the following reason:\n{#REMARKS#}\nBest regards,\nCompany Admin','Purchase Order Rejected',NULL,NULL,5,10),(9,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nA Project Budget Approval Request has been raised by {#RAISED_BY#} and waiting for your approval.Request details:\n\n- Project Name: {#PROJECT_NAME#}\n- Requested Amount: {#REQUESTED_AMOUNT#}\n\nYou can review & approve/reject it using the following link: {#EMAIL_LINK#}.\n\nBest regards,\nCompany Admin','Project Base Budget Approval Request',NULL,NULL,11,12),(10,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nA Project Budget Approval Request has been raised by {#RAISED_BY#} and has been approved by {#ACTIONED_BY#} and assigned to you for next level approval\nRequest details:\n\n- Project Name: {#PROJECT_NAME#}\n- Requested Amount: {#REQUESTED_AMOUNT#}\n\nApproval Level: {#APPROVAL_LEVEL#}.\nApproved Amount: {#APPROVED_AMOUNT#}.\nApproval Remark: {#REMARKS#}.\n\nYou can review & approve/reject it using the following link: {#EMAIL_LINK#}.\n\nBest regards,\nCompany Admin','Project Base Budget Next Level Approval',NULL,NULL,11,13),(11,'2025-08-04 09:33:11','2025-08-04 09:33:11','Dear {#TO_NAME#},\n\nYour Project Budget request for {#PROJECT_NAME#} has been approved by {#ACTIONED_BY#}.\nRequested Amount: {#REQUESTED_AMOUNT#}\n\nApproval Level: {#APPROVAL_LEVEL#}.\nApproved Amount: {#APPROVED_AMOUNT#}.\nAp